    cats = r['categories']
    if cats is None or (isinstance(cats, float) and pd.isna(cats)):
        continue
    if isinstance(cats, str):
        cat_list = [c.strip() for c in cats.split(',') if c.strip()]
    elif isinstance(cats, list):
        cat_list = [str(c).strip() for c in cats if str(c).strip()]
    else:
        continue
    for c in cat_list:
        rows.append((c, int(r['review_cnt'])))

cat_df = pd.DataFrame(rows, columns=['category','review_cnt'])
if cat_df.empty:
    top5 = []
else:
    top5 = (cat_df.groupby('category', as_index=False)['review_cnt'].sum()
                 .sort_values(['review_cnt','category'], ascending=[False, True])
                 .head(5))
    top5 = top5.to_dict(orient='records')

print('__RESULT__:')
print(json.dumps(top5))"}

